args.sparql:
SELECT ?awardLabel WHERE {
  wd:Q123456 rdfs:label ?awardLabel .
  FILTER (LANG(?awardLabel) = 'en')
  FILTER (CONTAINS(STR(?awardLabel), 'Best Coverage of Sport for People with a Disability'))
}

SELECT ?awardLabel WHERE {
  ?award rdfs:label ?awardLabel .
  FILTER (LANG(?awardLabel) = 'en')
  FILTER (CONTAINS(LCASE(STR(?awardLabel)), 'best coverage of sport for people with a disability'))
}

SELECT ?awardLabel WHERE {
  ?award rdfs:label ?awardLabel .
  FILTER (LANG(?awardLabel) = 'en')
  FILTER (LCASE(STR(?awardLabel)) = 'best coverage of sport for people with a disability')
}
